select name,organization,investor_type::public.lp_type,(case when n%5=0 then 'Cold' when n%3=0 then 'Hot' else 'Warm' end)::public.relationship_heat,
case investor_type when 'Family Office' then array['AI infrastructure','enterprise software','seed funds'] when 'Fund of Funds' then array['emerging managers','venture funds','portfolio construction'] when 'RIA' then array['private markets access','B2B software','co-investments'] when 'Angel Investor' then array['developer tools','applied AI','founder-led funds'] else array['mission alignment','responsible AI','economic mobility'] end,
array[(array['Fund I attribution','emerging manager risk','portfolio concentration','fee load','liquidity horizon','team bandwidth'])[((n-1)%6)+1]],introducer,event_name,current_date-(n%35),current_date+((n%18)-5),
(array['Send data room access','Share founder references','Schedule partner meeting','Provide attribution analysis','Send portfolio construction memo'])[((n-1)%5)+1],
array['Discussed fund strategy, differentiation, and team edge. LP asked detailed questions and requested a clear next step.','Follow-up meeting showed increased engagement. Reviewed pipeline, ownership targets, and reference process.'],
case when n%4=0 then 'Verbal indication pending diligence' when n%7=0 then 'Requested side-letter review' else null end,case when n%4=0 then 250000*(1+(n%5)) else null end,case when n%4=0 then 'indicated' when n%7=0 then 'reviewing' else null end from numbered;

select id,'meeting',meeting_notes[1],jsonb_build_object('source','demo seed','event',introduction_event),last_contact_date::timestamptz from public.lp_profiles where owner_id is null;
select id,next_action,next_follow_up,case when next_follow_up<current_date then 'overdue' else 'open' end from public.lp_profiles where owner_id is null;

-- Five additional records per allocator segment bring the demo to 75 LPs.

select p.id,'meeting',p.meeting_notes[1],jsonb_build_object('source','demo seed','event',p.introduction_event),p.last_contact_date::timestamptz from public.lp_profiles p where p.owner_id is null and not exists(select 1 from public.memories m where m.lp_id=p.id);
select p.id,p.next_action,p.next_follow_up,case when p.next_follow_up<current_date then 'overdue' else 'open' end from public.lp_profiles p where p.owner_id is null and not exists(select 1 from public.action_items a where a.lp_id=p.id);
